mapper.select:
select a.user_id from t_user_info a
                          inner join t_user_relation b on a.user_id = b.pos_user_id and b.par_user_id = #{userId}
    and b.distance > 0 AND a.is_valid =1

select a.user_id userId,b.distance bizType from t_user_info a
                                                    inner join t_user_relation b on a.user_id = b.pos_user_id and b.par_user_id = #{userId}
    and  b.distance >0 and b.distance <= #{depth} AND a.is_valid =1
